import { vm } from "../main.js"; // getting the vue instance with vuetify
/**
 * - Description -
 * ScreenService is a helper class that provides some facilities to handle the different screen
 * resolution of the app.
 *
 * - Usage -
 * Using ScreenService
 *
 * import ScreenService from '@/helpers/ScreenService.js'
 *
 */
export default {
    name: "ScreenService",
    methods: {
        getBreakpoint: getBreakpoint,
        // single
        isMobile: isMobile,
        isTablet: isTablet,
        isLaptop: isLaptop,
        isDesktop: isDesktop,
        isLargeScreen: isLargeScreen,
        // down
        tabletAndDown: tabletAndDown,
        laptopAndDown: laptopAndDown,
        desktopAndDown: desktopAndDown,
        // up
        tabletAndUp: tabletAndUp,
        laptopAndUp: laptopAndUp,
        desktopAndUp: desktopAndUp,
    },
};


function getBreakpoint() {
    console.debug("SCREEN.SERVICE - Current breakpoint", vm.$vuetify.breakpoint);
    return vm.$vuetify.breakpoint;
}

function getWindowHeight() {
    // in pixels
    console.debug("SCREEN.SERVICE - Current breakpoint", vm.$vuetify.breakpoint);
    return vm.$vuetify.breakpoint;
}

function getWindowWidth() {
    // in pixels
    console.debug("SCREEN.SERVICE - Current breakpoint", vm.$vuetify.breakpoint);
    return vm.$vuetify.width;
}

// single
function isMobile() {
    return vm.$vuetify.breakpoint.name === "xs";
}

function isTablet() {
    return vm.$vuetify.breakpoint.name === "sm";
}

function isLaptop() {
    return vm.$vuetify.breakpoint.name === "md";
}

function isDesktop() {
    return vm.$vuetify.breakpoint.name === "lg";
}

function isLargeScreen() {
    return vm.$vuetify.breakpoint.name === "xl";
}

// down
function tabletAndDown() {
    return vm.$vuetify.breakpoint.name === "xs" ||
        vm.$vuetify.breakpoint.name === "sm";
}

function laptopAndDown() {
    return vm.$vuetify.breakpoint.name === "xs" ||
        vm.$vuetify.breakpoint.name === "sm" ||
        vm.$vuetify.breakpoint.name === "md";
}

function desktopAndDown() {
    return vm.$vuetify.breakpoint.name === "xs" ||
        vm.$vuetify.breakpoint.name === "sm" ||
        vm.$vuetify.breakpoint.name === "md" ||
        vm.$vuetify.breakpoint.name === "lg";
}

// up
function tabletAndUp() {
    return vm.$vuetify.breakpoint.name === "sm" ||
        vm.$vuetify.breakpoint.name === "md" ||
        vm.$vuetify.breakpoint.name === "lg" ||
        vm.$vuetify.breakpoint.name === "xl";
}

function laptopAndUp() {
    return vm.$vuetify.breakpoint.name === "md" ||
        vm.$vuetify.breakpoint.name === "lg" ||
        vm.$vuetify.breakpoint.name === "xl";
}

function desktopAndUp() {
    return vm.$vuetify.breakpoint.name === "lg" ||
        vm.$vuetify.breakpoint.name === "xl";
}
