<template>
    <v-navigation-drawer
            v-model="drawer"
            dark
            temporary
            :disable-route-watcher="disableroutewatcher"
            :fixed="fixed"
            :hide-overlay="hideOverlay"
            :right="right"
            :clipped="$vuetify.breakpoint.lgAndUp"
            :mini-variant.sync="mini"
    >
            <v-layout fill-height row wrap pa-0>
                <v-flex xs12>
                    <v-layout align-start justify-end>
                        <v-btn icon flat small color="white" @click.stop="closeLeftNavBar()">
                            <v-icon>close</v-icon>
                        </v-btn>
                    </v-layout>
                </v-flex>
                <v-flex xs12>
                    <v-layout align-center>
                        <v-flex xs12>
                            <v-list class="pt-0" dense>
                                <v-list-tile
                                        v-for="element in elements"
                                        :key="element.title"
                                        @click.stop="clickLeftNavBarItem(element)"
                                >
                                    <v-list-tile-action>
                                        <v-icon>{{ element.icon }}</v-icon>
                                    </v-list-tile-action>

                                    <v-list-tile-content>
                                        <v-list-tile-title>{{ element.title }}</v-list-tile-title>
                                    </v-list-tile-content>
                                </v-list-tile>

                                <v-list-tile v-if="mini">
                                    <v-btn
                                            icon
                                            @click.stop="mini = false"
                                    >
                                        <v-icon>chevron_right</v-icon>
                                    </v-btn>
                                    <v-list-tile-content>
                                        <v-list-tile-title></v-list-tile-title>
                                    </v-list-tile-content>
                                </v-list-tile>
                            </v-list>
                        </v-flex>
                    </v-layout>
                </v-flex>
            </v-layout>
    </v-navigation-drawer>
</template>

<script>
    import LanguageChooser from "@/components/LanguageChooser";

    export default {
        name: "NavigationDrawer",
        components: {},
        props: ["drawer", "right", "elements"],
        computed: {},
        data() {
            return {
                disableroutewatcher: false,
                fixed: true,
                hideOverlay: true,
                mini: false
            };
        },
        methods: {
            closeLeftNavBar() {
                this.$store.dispatch("AppState/setLeftNavDrawer", false);
            },
            clickLeftNavBarItem(element) {
                this.$router.push(element.path);
                this.$store.dispatch("AppState/setLeftNavDrawer", false);
            }
        }
    };
</script>

<style lang="scss" scoped>
    .theme--dark.v-navigation-drawer {
        background-color: rgba(0, 0, 0, 0.95);

    }

    .theme--dark.v-list {
        background-color: transparent;
    }
</style>

